import{_ as n,c as t,o as s,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"命令: 监控与手动修剪 | opencode-dynamic-context-pruning","description":"掌握 DCP 的四个命令：查看会话分布、统计修剪效果和手动清理工具。","frontmatter":{"title":"命令: 监控与手动修剪 | opencode-dynamic-context-pruning","sidebarTitle":"命令","subtitle":"命令: 监控与手动修剪","description":"掌握 DCP 的四个命令：查看会话分布、统计修剪效果和手动清理工具。","tags":["DCP Commands","Token Monitoring","Manual Pruning"],"prerequisite":["start-getting-started","platforms-auto-pruning"],"order":3},"headers":[],"relativePath":"Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md","filePath":"Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"}'),o={name:"Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"};function i(l,e,r,p,d,c){return s(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="dcp-command-guide-monitor-and-manual-pruning" tabindex="-1">DCP Command Guide: Monitor and Manual Pruning <a class="header-anchor" href="#dcp-command-guide-monitor-and-manual-pruning" aria-label="Permalink to &quot;DCP Command Guide: Monitor and Manual Pruning&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Use <code>/dcp context</code> to view current session&#39;s token usage distribution</li><li>Use <code>/dcp stats</code> to view cumulative pruning statistics</li><li>Use <code>/dcp sweep [n]</code> to manually trigger pruning</li><li>Understand protected tools and files protection mechanisms</li><li>Learn token calculation strategies and savings effectiveness</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>In long conversations, token consumption accelerates, but you don&#39;t know:</p><ul><li>Where are the tokens being spent in the current session?</li><li>How much has DCP actually saved for you?</li><li>How to manually clean up tool outputs that are no longer needed?</li><li>Which tools are protected and won&#39;t be pruned?</li></ul><p>Without understanding these issues, you may not fully leverage DCP&#39;s optimization effects, and you might accidentally delete important information at critical moments.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><p>When you:</p><ul><li>Want to understand the token composition of the current session</li><li>Need to quickly clean up conversation history</li><li>Want to verify DCP&#39;s pruning effectiveness</li><li>Want to clean up context before starting a new task</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>DCP provides 4 slash commands to help you monitor and control token usage:</p><table tabindex="0"><thead><tr><th>Command</th><th>Purpose</th><th>Use Case</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>Display help</td><td>View when you forget commands</td></tr><tr><td><code>/dcp context</code></td><td>Analyze current session token distribution</td><td>Understand context composition</td></tr><tr><td><code>/dcp stats</code></td><td>View cumulative pruning statistics</td><td>Verify long-term effects</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>Manual tool pruning</td><td>Quickly reduce context size</td></tr></tbody></table><p><strong>Protection Mechanism</strong>:</p><p>All pruning operations automatically skip:</p><ul><li><strong>Protected Tools</strong>: <code>task</code>, <code>todowrite</code>, <code>todoread</code>, <code>discard</code>, <code>extract</code>, <code>batch</code>, <code>write</code>, <code>edit</code>, <code>plan_enter</code>, <code>plan_exit</code></li><li><strong>Protected Files</strong>: File paths matching <code>protectedFilePatterns</code> in configuration</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Protected tools and protected file settings can be customized through configuration files. See <a href="./../../start/configuration/">Configuration Guide</a> for details.</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-view-help-information" tabindex="-1">Step 1: View Help Information <a class="header-anchor" href="#step-1-view-help-information" aria-label="Permalink to &quot;Step 1: View Help Information&quot;">​</a></h3><p>Type <code>/dcp</code> in the OpenCode chat box.</p><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><p><strong>Checkpoint ✅</strong>: Confirm you see the descriptions of 3 subcommands.</p><h3 id="step-2-analyze-current-session-token-distribution" tabindex="-1">Step 2: Analyze Current Session Token Distribution <a class="header-anchor" href="#step-2-analyze-current-session-token-distribution" aria-label="Permalink to &quot;Step 2: Analyze Current Session Token Distribution&quot;">​</a></h3><p>Type <code>/dcp context</code> to view the current session&#39;s token usage.</p><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                  DCP Context Analysis                     │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><p><strong>Token Category Explanation</strong>:</p><table tabindex="0"><thead><tr><th>Category</th><th>Calculation</th><th>Description</th></tr></thead><tbody><tr><td><strong>System</strong></td><td><code>firstAssistant.input + cache.read - tokenizer(firstUserMessage)</code></td><td>System prompt</td></tr><tr><td><strong>Tools</strong></td><td><code>tokenizer(toolInputs + toolOutputs) - prunedTokens</code></td><td>Tool calls (pruned portion deducted)</td></tr><tr><td><strong>User</strong></td><td><code>tokenizer(all user messages)</code></td><td>All user messages</td></tr><tr><td><strong>Assistant</strong></td><td><code>total - system - user - tools</code></td><td>AI text output + reasoning tokens</td></tr></tbody></table><p><strong>Checkpoint ✅</strong>: Confirm you see the percentage and token count for each category.</p><h3 id="step-3-view-cumulative-pruning-statistics" tabindex="-1">Step 3: View Cumulative Pruning Statistics <a class="header-anchor" href="#step-3-view-cumulative-pruning-statistics" aria-label="Permalink to &quot;Step 3: View Cumulative Pruning Statistics&quot;">​</a></h3><p>Type <code>/dcp stats</code> to view the historical cumulative pruning effectiveness.</p><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                    DCP Statistics                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens pruned: ~15.2K</span></span>
<span class="line"><span>  Tools pruned:   12</span></span>
<span class="line"><span></span></span>
<span class="line"><span>All-time:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens saved:  ~284.5K</span></span>
<span class="line"><span>  Tools pruned:   156</span></span>
<span class="line"><span>  Sessions:       8</span></span></code></pre></div><p><strong>Statistics Explanation</strong>:</p><ul><li><strong>Session</strong>: Pruning data for current session (in memory)</li><li><strong>All-time</strong>: Cumulative data for all historical sessions (disk persisted)</li></ul><p><strong>Checkpoint ✅</strong>: Confirm you see pruning statistics for current session and historical cumulative data.</p><h3 id="step-4-manual-tool-pruning" tabindex="-1">Step 4: Manual Tool Pruning <a class="header-anchor" href="#step-4-manual-tool-pruning" aria-label="Permalink to &quot;Step 4: Manual Tool Pruning&quot;">​</a></h3><p>There are two ways to use <code>/dcp sweep</code>:</p><h4 id="method-1-prune-all-tools-since-last-user-message" tabindex="-1">Method 1: Prune All Tools Since Last User Message <a class="header-anchor" href="#method-1-prune-all-tools-since-last-user-message" aria-label="Permalink to &quot;Method 1: Prune All Tools Since Last User Message&quot;">​</a></h4><p>Type <code>/dcp sweep</code> (without parameters).</p><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept 8 tool(s) since previous user message.</span></span>
<span class="line"><span>Tokens saved: ~12,345</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/config.ts</span></span>
<span class="line"><span>  • Read: src/utils.ts</span></span>
<span class="line"><span>  • Bash: npm test</span></span>
<span class="line"><span>  • Read: package.json</span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span></code></pre></div><h4 id="method-2-prune-last-n-tools" tabindex="-1">Method 2: Prune Last N Tools <a class="header-anchor" href="#method-2-prune-last-n-tools" aria-label="Permalink to &quot;Method 2: Prune Last N Tools&quot;">​</a></h4><p>Type <code>/dcp sweep 5</code> to prune the last 5 tools.</p><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept last 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span>
<span class="line"><span>  • Bash: npm run build</span></span></code></pre></div><p><strong>Protected Tools Prompt</strong>:</p><p>If protected tools were skipped, the output will display:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swept 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span>(2 protected tool(s) skipped)</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Protected tools (like <code>write</code>, <code>edit</code>) and protected file paths are automatically skipped and will not be pruned.</p></div><p><strong>Checkpoint ✅</strong>: Confirm you see the list of pruned tools and the amount of saved tokens.</p><h3 id="step-5-review-pruning-effectiveness-again" tabindex="-1">Step 5: Review Pruning Effectiveness Again <a class="header-anchor" href="#step-5-review-pruning-effectiveness-again" aria-label="Permalink to &quot;Step 5: Review Pruning Effectiveness Again&quot;">​</a></h3><p>After pruning, type <code>/dcp context</code> again to view the new token distribution.</p><p><strong>You should see</strong>:</p><ul><li><code>Tools</code> category percentage decreased</li><li>Increased number of pruned tools in <code>Summary</code></li><li>Reduced <code>Current context</code> total</li></ul><p><strong>Checkpoint ✅</strong>: Confirm token usage has significantly decreased.</p><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="❌-mistake-accidentally-deleting-important-tools" tabindex="-1">❌ Mistake: Accidentally Deleting Important Tools <a class="header-anchor" href="#❌-mistake-accidentally-deleting-important-tools" aria-label="Permalink to &quot;❌ Mistake: Accidentally Deleting Important Tools&quot;">​</a></h3><p><strong>Scenario</strong>: You just used the <code>write</code> tool to create a critical file, then executed <code>/dcp sweep</code>.</p><p><strong>Wrong Result</strong>: The <code>write</code> tool is pruned, and the AI may not know the file was created.</p><p><strong>Correct Approach</strong>:</p><ul><li>Tools like <code>write</code>, <code>edit</code> are protected by default</li><li>Don&#39;t manually modify <code>protectedTools</code> configuration to remove these tools</li><li>Wait a few turns after completing critical tasks before cleaning up</li></ul><h3 id="❌-mistake-pruning-at-the-wrong-time" tabindex="-1">❌ Mistake: Pruning at the Wrong Time <a class="header-anchor" href="#❌-mistake-pruning-at-the-wrong-time" aria-label="Permalink to &quot;❌ Mistake: Pruning at the Wrong Time&quot;">​</a></h3><p><strong>Scenario</strong>: The conversation just started, and you execute <code>/dcp sweep</code> with only a few tool calls.</p><p><strong>Wrong Result</strong>: Very few tokens saved, and context coherence may be affected.</p><p><strong>Correct Approach</strong>:</p><ul><li>Wait until the conversation progresses to a certain extent (e.g., 10+ tool calls) before cleaning</li><li>Clean up previous round&#39;s tool outputs before starting a new task</li><li>Use <code>/dcp context</code> to determine if cleaning is worthwhile</li></ul><h3 id="❌-mistake-over-relying-on-manual-pruning" tabindex="-1">❌ Mistake: Over-relying on Manual Pruning <a class="header-anchor" href="#❌-mistake-over-relying-on-manual-pruning" aria-label="Permalink to &quot;❌ Mistake: Over-relying on Manual Pruning&quot;">​</a></h3><p><strong>Scenario</strong>: You manually execute <code>/dcp sweep</code> in every conversation.</p><p><strong>Wrong Result</strong>:</p><ul><li>Automatic pruning strategies (deduplication, overwrite writes, error clearing) are wasted</li><li>Increases operational burden</li></ul><p><strong>Correct Approach</strong>:</p><ul><li>Keep automatic pruning strategies enabled by default (config: <code>strategies.*.enabled</code>)</li><li>Use manual pruning as a supplement only when necessary</li><li>Verify automatic pruning effectiveness through <code>/dcp stats</code></li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>DCP&#39;s 4 commands help you monitor and control token usage:</p><table tabindex="0"><thead><tr><th>Command</th><th>Core Function</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>Display help information</td></tr><tr><td><code>/dcp context</code></td><td>Analyze current session token distribution</td></tr><tr><td><code>/dcp stats</code></td><td>View cumulative pruning statistics</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>Manual tool pruning</td></tr></tbody></table><p><strong>Token Calculation Strategy</strong>:</p><ul><li>System: System prompt (calculated from first response)</li><li>Tools: Tool inputs and outputs (pruned portion deducted)</li><li>User: All user messages (estimated)</li><li>Assistant: AI output + reasoning tokens (residual)</li></ul><p><strong>Protection Mechanism</strong>:</p><ul><li>Protected tools: <code>task</code>, <code>todowrite</code>, <code>todoread</code>, <code>discard</code>, <code>extract</code>, <code>batch</code>, <code>write</code>, <code>edit</code>, <code>plan_enter</code>, <code>plan_exit</code></li><li>Protected files: Configured glob patterns</li><li>All pruning operations automatically skip these contents</li></ul><p><strong>Best Practices</strong>:</p><ul><li>Regularly view <code>/dcp context</code> to understand token composition</li><li>Execute <code>/dcp sweep</code> before new tasks to clean up history</li><li>Rely on automatic pruning, use manual pruning as a supplement</li><li>Verify long-term effectiveness through <code>/dcp stats</code></li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>Next, we&#39;ll learn <strong><a href="./../../advanced/protection/">Protection Mechanism</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How turn protection prevents accidental pruning</li><li>How to customize the protected tools list</li><li>Protected file pattern configuration methods</li><li>Special handling for subagent sessions</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>/dcp help command</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>19-32</td></tr><tr><td>/dcp context command</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>238-247</td></tr><tr><td>Token calculation strategy</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>5-38</td></tr><tr><td>/dcp stats command</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/stats.ts" target="_blank" rel="noreferrer"><code>lib/commands/stats.ts</code></a></td><td>46-67</td></tr><tr><td>/dcp sweep command</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/sweep.ts" target="_blank" rel="noreferrer"><code>lib/commands/sweep.ts</code></a></td><td>123-259</td></tr><tr><td>Protected tools configuration</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>461</td></tr><tr><td>Default protected tools list</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>150-151</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>DEFAULT_PROTECTED_TOOLS</code>: Default protected tools list</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>handleHelpCommand()</code>: Handle /dcp help command</li><li><code>handleContextCommand()</code>: Handle /dcp context command</li><li><code>analyzeTokens()</code>: Calculate token count for each category</li><li><code>handleStatsCommand()</code>: Handle /dcp stats command</li><li><code>handleSweepCommand()</code>: Handle /dcp sweep command</li><li><code>buildToolIdList()</code>: Build tool ID list</li></ul></details>`,88)])])}const g=n(o,[["render",i]]);export{h as __pageData,g as default};
